    let dangerous_chars = ['|', '&', ';', '$', '`', '!', '(', ')', '{', '}', '[', ']',
                           '<', '>', '\'', '"', '\\', '\n', '\r', '\0', '*', '?', '~'];
    for ch in dangerous_chars {
        if filename_str.contains(ch) {
            return Err(ConversionError::InvalidFilename(
                format!("Filename contains forbidden character: '{}'", ch),
            ));
        }
    }

    // Ensure the filename is not empty
    if filename_str.trim().is_empty() {
        return Err(ConversionError::InvalidFilename(
            "Filename is empty".to_string(),
        ));
    }

    let canonical = path.to_path_buf();
    Ok(canonical)
