    let image_formats = ["png", "jpg", "jpeg", "gif", "bmp", "tiff", "webp", "svg"];
    let audio_formats = ["mp3", "wav", "ogg", "flac"];
    let video_formats = ["mp4", "avi", "mkv", "mov", "webm"];
    let document_formats = ["pdf", "txt", "csv", "json", "xml", "html", "md"];

    let is_image_source = image_formats.contains(&source_ext.as_str());
    let is_image_target = image_formats.contains(&target_format.as_str());
    let is_audio_source = audio_formats.contains(&source_ext.as_str());
    let is_audio_target = audio_formats.contains(&target_format.as_str());
    let is_video_source = video_formats.contains(&source_ext.as_str());
    let is_video_target = video_formats.contains(&target_format.as_str());
    let is_doc_source = document_formats.contains(&source_ext.as_str());
